codeExercises.solution:
const myPromise = new Promise((resolve, reject) => {
  setTimeout(() => {
    resolve("Hello World");
  }, 1000);
});

async function fetchData() {
  try {
    const result = await myPromise;
    console.log(result); // Hello World
  } catch (error) {
    console.error(error);
  }
}

fetchData();
